<?php $certificate = $certificate ?? []; $meta = $meta ?? []; $items = $items ?? []; $statuses = $statuses ?? []; $revisions = $revisions ?? []; $history = $history ?? []; $statusClasses = [0 => 'bg-secondary', 1 => 'bg-info', 2 => 'bg-success', 6 => 'bg-danger']; ?>
<style>@media print {.no-print{display:none!important}.card{border:0}.page-header{display:none}}</style>
<div class="page-header no-print"><h1><?= escapeHtml($certificate['document_number'] ?? '') ?></h1><div class="btn-group"><a href="/certificate-of-origins" class="btn btn-outline-secondary">Back</a><a href="/certificate-of-origins/<?= (int) ($certificate['id'] ?? 0) ?>/edit" class="btn btn-outline-primary">Edit</a><button onclick="window.print()" class="btn btn-outline-dark">Print</button></div></div>
<div class="card"><div class="card-body"><div class="text-center mb-4"><h2>CERTIFICATE OF ORIGIN</h2></div><div class="row mb-3"><div class="col-md-6"><strong>Certificate No:</strong> <?= escapeHtml($certificate['document_number'] ?? '') ?><br><strong>Date:</strong> <?= escapeHtml($certificate['document_date'] ?? '') ?><br><strong>Status:</strong> <span class="badge <?= escapeHtml($statusClasses[(int) ($certificate['status'] ?? 0)] ?? 'bg-secondary') ?>"><?= escapeHtml($statuses[(int) ($certificate['status'] ?? 0)] ?? 'Unknown') ?></span><br><strong>Issuing Authority:</strong> <?= escapeHtml($meta['issuing_authority'] ?? '') ?></div><div class="col-md-6"><strong>Country of Origin:</strong> <?= escapeHtml($meta['country_of_origin'] ?? '') ?><br><strong>Destination Country:</strong> <?= escapeHtml($meta['destination_country'] ?? '') ?><br><strong>Exporter:</strong> <?= escapeHtml($meta['exporter'] ?? '') ?><br><strong>Consignee:</strong> <?= escapeHtml($meta['consignee'] ?? '') ?></div></div><div><strong>Declaration:</strong><br><?= nl2br(escapeHtml($meta['declaration'] ?? '')) ?></div><div class="table-responsive mt-3"><table class="table table-bordered"><thead><tr><th>#</th><th>Product</th><th>HS Code</th><th>Quantity</th></tr></thead><tbody><?php foreach ($items as $index => $item): ?><tr><td><?= $index + 1 ?></td><td><?= escapeHtml($item['product_name'] ?? '') ?></td><td><?= escapeHtml($item['hsn_code'] ?? '') ?></td><td><?= number_format((float) ($item['quantity'] ?? 0), 3) ?></td></tr><?php endforeach; ?></tbody></table></div><div><strong>Remarks:</strong><br><?= nl2br(escapeHtml($certificate['remarks'] ?? '')) ?></div></div></div>
<div class="row mt-3 no-print"><div class="col-md-6"><div class="card"><div class="card-body"><h5>Revision History</h5><?php foreach ($revisions as $revision): ?><div>Rev <?= (int) $revision['revision_number'] ?> - <?= escapeHtml($revision['created_at']) ?> - <?= escapeHtml($revision['revision_notes'] ?? '') ?></div><?php endforeach; ?><form method="post" action="/certificate-of-origins/<?= (int) ($certificate['id'] ?? 0) ?>/revise" class="mt-2"><?= csrfToken() ?><input type="text" name="revision_notes" class="form-control mb-2" placeholder="Revision notes"><button class="btn btn-sm btn-primary">Save Revision</button></form></div></div></div><div class="col-md-6"><div class="card"><div class="card-body"><h5>Status History</h5><form method="post" action="/certificate-of-origins/<?= (int) ($certificate['id'] ?? 0) ?>/status" class="row g-2"><?= csrfToken() ?><div class="col-md-5"><select name="status" class="form-select"><?php foreach ($statuses as $statusId => $statusName): ?><option value="<?= (int) $statusId ?>" <?= (int) ($certificate['status'] ?? 0) === (int) $statusId ? 'selected' : '' ?>><?= escapeHtml($statusName) ?></option><?php endforeach; ?></select></div><div class="col-md-5"><input type="text" name="remarks" class="form-control" placeholder="Status remarks"></div><div class="col-md-2"><button class="btn btn-primary">Update</button></div></form><?php foreach ($history as $entry): ?><div class="small text-muted mt-1"><?= escapeHtml($entry['created_at']) ?>: <?= escapeHtml($statuses[(int) $entry['new_status']] ?? 'Unknown') ?> <?= escapeHtml($entry['remarks'] ?? '') ?></div><?php endforeach; ?></div></div></div></div>